 {"id":"bd-2mdn","title":"Tests for atomic Status::update behavior","description":"## Task Description

Add comprehensive tests verifying the Status::update behavior after the race condition fix. Tests must include detailed logging and concurrent stress scenarios.

## Test Coverage

### Unit Tests (in src/interactive.rs)

```rust
#[cfg(test)]
mod status_tests {
    use super::*;
    use std::sync::Arc;
    use std::thread;
    use std::time::Duration;

    #[test]
    fn test_status_update_single_thread() {
        println\!("[TEST] Single-threaded Status::update");

        let console = Arc::new(Console::new());

        // Skip if not interactive
        if \!console.is_interactive() {
            println\!("[TEST] Skipping: console not interactive");
            return;
        }

        let status = Status::new(&console, "Initial").unwrap();
        println\!("[TEST] Created status with initial message");

        status.update("Updated message");
        println\!("[TEST] Called update()");

        // Wait for refresh cycle
        thread::sleep(Duration::from_millis(150));
        println\!("[TEST] Waited 150ms for refresh");

        // No way to read message back, but should not panic
        println\!("[TEST] PASS: Status::update works in single thread");
    }

    #[test]
    fn test_status_update_rapid_sequence() {
        println\!("[TEST] Rapid sequential Status::update calls");

        let console = Arc::new(Console::new());
        if \!console.is_interactive() {
            println\!("[TEST] Skipping: console not interactive");
            return;
        }

        let status = Status::new(&console, "Start").unwrap();

        for i in 0..100 {
            status.update(format\!("Message {}", i));
        }
        println\!("[TEST] Called update() 100 times rapidly");

        thread::sleep(Duration::from_millis(200));
        println\!("[TEST] PASS: Rapid updates dont crash");
    }

    #[test]
    fn test_status_update_concurrent() {
        println\!("[TEST] Concurrent Status::update from multiple threads");

        let console = Arc::new(Console::new());
        if \!console.is_interactive() {
            println\!("[TEST] Skipping: console not interactive");
            return;
        }

        let status = Arc::new(Status::new(&console, "Start").unwrap());

        let handles: Vec<_> = (0..4).map(|i| {
            let status = Arc::clone(&status);
            thread::spawn(move || {
                for j in 0..50 {
                    status.update(format\!("Thread {} msg {}", i, j));
                    thread::sleep(Duration::from_micros(100));
                }
                println\!("[Thread {}] Completed 50 updates", i);
            })
        }).collect();

        for (i, h) in handles.into_iter().enumerate() {
            h.join().expect(&format\!("Thread {} panicked", i));
            println\!("[Thread {}] Joined", i);
        }

        println\!("[TEST] PASS: Concurrent updates work");
    }
}
```

### E2E Test File: tests/e2e_status_update.rs

```rust
//\! End-to-end tests for Status::update race condition fix.
//\!
//\! These tests verify that:
//\! 1. Status::update is thread-safe
//\! 2. Concurrent updates dont cause crashes
//\! 3. Final message is eventually consistent
//\! 4. No visual glitches under stress
//\!
//\! Run with: cargo test --test e2e_status_update -- --nocapture

use rich_rust::interactive::Status;
use rich_rust::{Console, ConsoleBuilder};
use std::sync::{Arc, Barrier, Mutex, atomic::{AtomicUsize, Ordering}};
use std::thread;
use std::time::{Duration, Instant};
use std::io::Write;

struct SharedBuffer(Arc<Mutex<Vec<u8>>>);
impl Write for SharedBuffer {
    fn write(&mut self, buf: &[u8]) -> std::io::Result<usize> {
        self.0.lock().unwrap().extend_from_slice(buf);
        Ok(buf.len())
    }
    fn flush(&mut self) -> std::io::Result<()> { Ok(()) }
}

// ============================================================================
// TEST 1: Basic concurrent safety
// ============================================================================

#[test]
fn test_e2e_status_concurrent_updates() {
    println\!("\n");
    println\!("=".repeat(70));
    println\!("E2E TEST: Status concurrent update safety");
    println\!("=".repeat(70));

    let buffer = Arc::new(Mutex::new(Vec::new()));
    let console = Arc::new(ConsoleBuilder::new()
        .force_terminal(true)
        .force_interactive(true)
        .writer(SharedBuffer(Arc::clone(&buffer)))
        .build());

    println\!("\n[PHASE 1] Create Status and verify it starts");
    println\!("-".repeat(50));
    let status = match Status::new(&console, "Starting...") {
        Ok(s) => {
            println\!("  Status created successfully");
            Arc::new(s)
        }
        Err(e) => {
            println\!("  Status creation failed (expected in CI): {:?}", e);
            return;
        }
    };
    println\!("  ✓ Phase 1 PASSED\n");

    println\!("[PHASE 2] Concurrent updates from 4 threads");
    println\!("-".repeat(50));
    let barrier = Arc::new(Barrier::new(4));
    let update_count = Arc::new(AtomicUsize::new(0));

    let handles: Vec<_> = (0..4).map(|i| {
        let status = Arc::clone(&status);
        let barrier = Arc::clone(&barrier);
        let count = Arc::clone(&update_count);

        thread::spawn(move || {
            barrier.wait();
            let start = Instant::now();

            for j in 0..100 {
                status.update(format\!("T{}:{}", i, j));
                count.fetch_add(1, Ordering::SeqCst);
            }

            let elapsed = start.elapsed();
            println\!("  [Thread {}] 100 updates in {:?}", i, elapsed);
        })
    }).collect();

    for (i, h) in handles.into_iter().enumerate() {
        h.join().expect(&format\!("Thread {} should not panic", i));
    }

    let total = update_count.load(Ordering::SeqCst);
    println\!("  Total updates: {}", total);
    assert_eq\!(total, 400);
    println\!("  ✓ Phase 2 PASSED\n");

    println\!("[PHASE 3] Final update and clean stop");
    println\!("-".repeat(50));
    // Status dropped here, should stop cleanly
    drop(status);
    println\!("  Status dropped (Live stopped)");
    println\!("  ✓ Phase 3 PASSED\n");

    println\!("=".repeat(70));
    println\!("✓ E2E TEST PASSED: Concurrent Status::update is safe");
    println\!("=".repeat(70));
    println\!();
}

// ============================================================================
// TEST 2: Update during refresh cycle
// ============================================================================

#[test]
fn test_e2e_status_update_refresh_timing() {
    println\!("\n");
    println\!("=".repeat(70));
    println\!("E2E TEST: Status update during refresh cycles");
    println\!("=".repeat(70));

    let buffer = Arc::new(Mutex::new(Vec::new()));
    let console = Arc::new(ConsoleBuilder::new()
        .force_terminal(true)
        .force_interactive(true)
        .writer(SharedBuffer(Arc::clone(&buffer)))
        .build());

    println\!("\n[PHASE 1] Create Status with 10Hz refresh");
    println\!("-".repeat(50));
    let status = match Status::new(&console, "Tick 0") {
        Ok(s) => Arc::new(s),
        Err(_) => {
            println\!("  Skipping (not interactive)");
            return;
        }
    };
    println\!("  Refresh rate: 10 Hz (100ms per frame)");
    println\!("  ✓ Phase 1 PASSED\n");

    println\!("[PHASE 2] Update faster than refresh rate");
    println\!("-".repeat(50));
    let start = Instant::now();
    for i in 0..50 {
        status.update(format\!("Tick {}", i));
        thread::sleep(Duration::from_millis(20)); // 50Hz updates
    }
    let elapsed = start.elapsed();
    println\!("  50 updates at ~50Hz completed in {:?}", elapsed);
    println\!("  Some updates may be skipped visually (expected)");
    println\!("  ✓ Phase 2 PASSED\n");

    println\!("[PHASE 3] Update slower than refresh rate");
    println\!("-".repeat(50));
    for i in 50..55 {
        status.update(format\!("Slow tick {}", i));
        thread::sleep(Duration::from_millis(200)); // 5Hz updates
    }
    println\!("  5 slow updates completed");
    println\!("  Each should be visible for ~2 refresh cycles");
    println\!("  ✓ Phase 3 PASSED\n");

    println\!("=".repeat(70));
    println\!("✓ E2E TEST PASSED: Update/refresh timing works correctly");
    println\!("=".repeat(70));
    println\!();
}

// ============================================================================
// TEST 3: Eventual consistency verification
// ============================================================================

#[test]
fn test_e2e_status_eventual_consistency() {
    println\!("\n");
    println\!("=".repeat(70));
    println\!("E2E TEST: Status eventual consistency");
    println\!("=".repeat(70));

    let buffer = Arc::new(Mutex::new(Vec::new()));
    let console = Arc::new(ConsoleBuilder::new()
        .force_terminal(true)
        .force_interactive(true)
        .writer(SharedBuffer(Arc::clone(&buffer)))
        .build());

    println\!("\n[PHASE 1] Set up status with message tracking");
    println\!("-".repeat(50));
    let status = match Status::new(&console, "Initial") {
        Ok(s) => Arc::new(s),
        Err(_) => {
            println\!("  Skipping (not interactive)");
            return;
        }
    };
    println\!("  ✓ Phase 1 PASSED\n");

    println\!("[PHASE 2] Burst update then wait");
    println\!("-".repeat(50));
    for i in 0..10 {
        status.update(format\!("Burst {}", i));
    }
    status.update("FINAL MESSAGE");
    println\!("  Sent 10 burst updates + final");

    // Wait for refresh cycle to pick up final message
    thread::sleep(Duration::from_millis(200));
    println\!("  Waited 200ms for refresh");

    // Check output contains final message
    let output = String::from_utf8_lossy(&buffer.lock().unwrap()).to_string();
    println\!("  Output contains FINAL: {}", output.contains("FINAL"));
    println\!("  ✓ Phase 2 PASSED\n");

    println\!("=".repeat(70));
    println\!("✓ E2E TEST PASSED: Final message is eventually displayed");
    println\!("=".repeat(70));
    println\!();
}
```

