// TEST 2: Style cache survives poison and concurrent access
// ============================================================================

#[test]
fn test_e2e_style_cache_poison_recovery() {
    println\!("\n");
    println\!("=".repeat(70));
    println\!("E2E TEST: Style cache poison recovery");
    println\!("=".repeat(70));

    println\!("\n[PHASE 1] Warm up style cache");
    println\!("-".repeat(50));
    let styles = ["bold", "italic", "red", "blue on white", "bold red"];
    for s in &styles {
        let parsed = Style::parse(s);
        println\!("  Parsed '{}' -> {:?}", s, parsed.is_some());
    }
    println\!("  ✓ Phase 1 PASSED\n");

    println\!("[PHASE 2] Concurrent parsing with one panicking thread");
    println\!("-".repeat(50));
    let results = Arc::new(Mutex::new(Vec::new()));

    let handles: Vec<_> = (0..4).map(|i| {
        let results = Arc::clone(&results);
        thread::spawn(move || {
            if i == 1 {
                // Parse some styles then panic
                for _ in 0..10 {
                    let _ = Style::parse("bold");
                }
                panic\!("Thread 1 intentional panic mid-parse");
            }

            let mut count = 0;
            for j in 0..50 {
                if Style::parse(&format\!("color{}", j % 10)).is_some() {
                    count += 1;
                }
            }
            results.lock().unwrap().push((i, count));
            println\!("  [Thread {}] Parsed {} styles", i, count);
        })
    }).collect();

    for (i, h) in handles.into_iter().enumerate() {
        match h.join() {
            Ok(()) => println\!("  [Thread {}] Joined OK", i),
            Err(_) => println\!("  [Thread {}] Panicked (expected)", i),
        }
    }

    let results = results.lock().unwrap();
    println\!("  Successful threads: {}", results.len());
    assert_eq\!(results.len(), 3, "Three threads should complete");
    println\!("  ✓ Phase 2 PASSED\n");

    println\!("[PHASE 3] Style parsing still works");
    println\!("-".repeat(50));
    let test_style = Style::parse("bold italic underline");
    println\!("  Parsed 'bold italic underline': {:?}", test_style.is_some());
    assert\!(test_style.is_some());
    println\!("  ✓ Phase 3 PASSED\n");

    println\!("=".repeat(70));
    println\!("✓ E2E TEST PASSED: Style cache handles poison gracefully");
    println\!("=".repeat(70));
    println\!();
}

