#[test]
fn test_e2e_live_display_stability() {
    println\!("\n");
    println\!("=".repeat(70));
    println\!("E2E TEST: Live display stability under stress");
    println\!("=".repeat(70));

    let buffer = SharedBuffer::new();
    let console = Arc::new(ConsoleBuilder::new()
        .force_terminal(true)
        .force_interactive(true)
        .width(80)
        .writer(buffer.clone())
        .build());

    println\!("\n[PHASE 1] Create and start Live display");
    println\!("-".repeat(50));
    let live = Live::with_options(
        Arc::clone(&console),
        LiveOptions {
            refresh_per_second: 10.0,
            transient: true,
            ..Default::default()
        }
    );

    let counter = Arc::new(Mutex::new(0));
    let counter_clone = Arc::clone(&counter);

    let live = live.get_renderable(move || {
        let count = *counter_clone.lock().unwrap();
        Box::new(rich_rust::renderables::Text::new(format\!("Count: {}", count)))
    });

    live.start(true).expect("Live should start");
    println\!("  Live display started");
    println\!("  ✓ Phase 1 PASSED\n");

    println\!("[PHASE 2] Update from multiple threads, one panics");
    println\!("-".repeat(50));
    let handles: Vec<_> = (0..3).map(|i| {
        let counter = Arc::clone(&counter);
        thread::spawn(move || {
            if i == 1 {
                thread::sleep(Duration::from_millis(50));
                panic\!("Thread 1 panic during live update");
            }
            for j in 0..10 {
                {
                    let mut c = counter.lock().unwrap();
                    *c += 1;
                }
                thread::sleep(Duration::from_millis(20));
            }
            println\!("  [Thread {}] Completed 10 updates", i);
        })
    }).collect();

    for (i, h) in handles.into_iter().enumerate() {
        match h.join() {
            Ok(()) => println\!("  [Thread {}] Joined OK", i),
            Err(_) => println\!("  [Thread {}] Panicked (expected)", i),
        }
    }
    println\!("  ✓ Phase 2 PASSED\n");

    println\!("[PHASE 3] Verify Live still works and stop cleanly");
    println\!("-".repeat(50));
    let final_count = *counter.lock().unwrap();
    println\!("  Final counter value: {}", final_count);
    live.stop().expect("Live should stop cleanly");
    println\!("  Live stopped successfully");
    println\!("  ✓ Phase 3 PASSED\n");

    println\!("=".repeat(70));
    println\!("✓ E2E TEST PASSED: Live display remains stable");
    println\!("=".repeat(70));
    println\!();
}
